    /// measures: food eaten 05:00 this day -> 05:00 next day [kcal]
    var energyBalanceKcal: Int?
    /// Total energy eaten across the waking day (05:00 to 05:00, so a midnight snack counts toward the day it belongs to). Only written once the day is over — never a partial total.
    /// measures: food eaten 05:00 this day -> 05:00 next day [kcal]
    var totalCalsIn: Double?
