/// Body composition (scale screenshot)
struct Body: Codable, Hashable {
    /// Body weight. Direction is deliberately neutral — whether up is good depends on a goal this data doesn't contain. Day-to-day swings are mostly water; read the trend, not the delta.
    /// measures: measured on this morning, fasted [kg]
    var weightKg: Double?
    /// Body mass index as computed by the scale. Low information given body fat and lean mass are measured directly.
    /// measures: measured on this morning, fasted
    var bmi: Double?
    /// Body fat percentage from bioimpedance. Hydration-sensitive, so trust the multi-day trend over any single reading.
    /// measures: measured on this morning, fasted [%]
    var bodyFatPct: Double?
    /// Fat stored under the skin, as a percentage.
    /// measures: measured on this morning, fasted [%]
    var subcutaneousFatPct: Double?
    /// Visceral fat index (a unitless scale value, not a percentage or a mass). Fat around the organs; the most metabolically relevant fat measure here.
    /// measures: measured on this morning, fasted [index]
    var visceralFat: Double?
    /// Total body water. Explains much of the day-to-day noise in weight and body-fat readings.
    /// measures: measured on this morning, fasted [%]
    var bodyWaterPct: Double?
    /// Skeletal muscle mass. Should hold or rise while weight falls — that is what successful recomposition looks like.
    /// measures: measured on this morning, fasted [kg]
    var muscleMassKg: Double?
    /// Bone mass. Changes very slowly; effectively a constant.
    /// measures: measured on this morning, fasted [kg]
    var boneMassKg: Double?
    /// Basal metabolic rate as estimated by the scale from lean mass. Compare against Fitbit's measured total_cals_out.
    /// measures: measured on this morning, fasted [kcal]
    var bmrKcal: Double?
    /// The scale's proprietary 'metabolic age' estimate. Vendor marketing metric — low scientific value; kept for completeness.
    /// measures: measured on this morning, fasted [years]
    var metabolicAge: Double?
    /// weight_kg x (1 - body_fat_pct/100). Everything that isn't fat. The number that should stay flat while you cut.
    /// measures: measured on this morning, fasted [kg]
    var leanMassKg: Double?
    /// Local timestamp of the weigh-in, read off the app screen. The hour is signal: a fasted 07:00 reading and a 21:00 one are not comparable.
    /// measures: measured on this morning, fasted
    var bodyMeasuredAt: String?

    enum CodingKeys: String, CodingKey {
        case weightKg = "weight_kg"
        case bmi = "bmi"
        case bodyFatPct = "body_fat_pct"
        case subcutaneousFatPct = "subcutaneous_fat_pct"
        case visceralFat = "visceral_fat"
        case bodyWaterPct = "body_water_pct"
        case muscleMassKg = "muscle_mass_kg"
        case boneMassKg = "bone_mass_kg"
        case bmrKcal = "bmr_kcal"
        case metabolicAge = "metabolic_age"
        case leanMassKg = "lean_mass_kg"
        case bodyMeasuredAt = "body_measured_at"
    }
}

/// One day. `date` is the local civil day (Europe/Lisbon).
struct HealthDay: Codable, Hashable, Identifiable {
    var id: String { date }
    var date: String
    var selfReport: SelfReport?
    var sleep: Sleep?
    var recovery: Recovery?
    var activity: Activity?
    var nutrition: Nutrition?
    var body: Body?

    enum CodingKeys: String, CodingKey {
        case date
        case selfReport = "self_report"
        case sleep = "sleep"
        case recovery = "recovery"
        case activity = "activity"
        case nutrition = "nutrition"
        case body = "body"
    }
}

/// The GET /daily envelope.
struct DailyResponse: Codable {
    var from: String
    var to: String
    var count: Int
    var blocks: [String]
    var days: [HealthDay]
}
